class Solution:
    def minLengthAfterRemovals(self, nums: List[int]) -> int:
        n = len(nums)
        i, j = 0, (n + 1) // 2
        count = 0

        while j < n:
            if nums[i] < nums[j]:
                count += 2
                i += 1
            j += 1

        return n - count
